UPDATE coupon_activation_code
SET status      = #{toStatus},
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE batch_id = #{batchId}
  AND is_deleted = 0
  AND status = #{fromStatus}

UPDATE coupon_activation_code
SET status      = #{toStatus},
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE id = #{codeId}
  AND is_deleted = 0
  AND status = #{fromStatus}

UPDATE coupon_activation_code
SET is_deleted  = 1,
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE id = #{codeId}
  AND is_deleted = 0

UPDATE coupon_activation_code
SET is_deleted  = 1,
    update_time = #{updateTime},
    update_by   = #{operatorId}
WHERE batch_id = #{batchId}
  AND is_deleted = 0
